import { Chip, Grid, makeStyles, Tooltip, Typography } from '@material-ui/core'
import { Rating } from '@material-ui/lab';
import StarBorderIcon from '@material-ui/icons/StarBorder';
import React from 'react'

const useStyles = makeStyles(theme => ({
        chip: {
            margin: theme.spacing(0.35),
            fontSize: theme.typography.body1.fontSize,
            fontWeight: theme.typography.body1.fontWeight
        },
        heading: {
            fontFamily: "Lato",
            fontWeight: "bold",
        }

    })
)

function Skills({ data, className }) {
    const classes = useStyles()
    return (<Grid container spacing={2} className={`${className}`}>
        {Object.values(data).map((item, idx) => (
            <Grid key={idx} item container xs={12} sm={4} alignContent="flex-start">
                <Grid item xs={12}>
                    <Typography gutterBottom variant="h5" align="center" className={classes.heading}>{item.display}</Typography>
                </Grid>
                <Grid item container xs={12} justifyContent="center" alignContent="flex-start">
                    {
                        item.values.map((item, idx) => <Tooltip key={idx} title={
                            <Rating
                                name="customized-empty"
                                defaultValue={item.score}
                                precision={0.5}
                                emptyIcon={<StarBorderIcon fontSize="inherit" />}
                                readOnly
                            />

                        }>
                            <Chip className={classes.chip} color={item.score===5?"primary":item.score>4?"secondary":"default"} variant="outlined" label={item.name} />
                        </Tooltip>)
                    }
                </Grid>
            </Grid>
            )
        )}
    </Grid>
    )
}

export default Skills