import { Card, CardContent, CardHeader, CardActions, Chip, Grid, makeStyles, Tooltip, Typography, IconButton, Collapse } from '@material-ui/core'
import React, { useState } from 'react'
import GitHubIcon from '@material-ui/icons/GitHub';
import LaunchIcon from '@material-ui/icons/Launch';
import ExpandMoreIcon from '@material-ui/icons/ExpandMore';

const useStyles = makeStyles(theme => ({
        card: {
            background: theme.palette.background.default,
            height: '100%',
            display: "flex",
            flexDirection: "column",
        },
        chip: {
            margin: theme.spacing(0.35),
            fontSize: theme.typography.body2.fontSize,
            fontWeight: theme.typography.body2.fontWeight
        },
        cardHeader: {
            "& .MuiCardHeader-content": {
                flex: "1 1 auto",
                width: '100%',
            },
        },
        cardActions: {
            justifyContent: "space-between",
        },
        content: {
            flex: 1
        },
        achievements: {
            listStyleType: "circle",
            paddingLeft: theme.spacing(2)
        }
    })
)

function SingleProject({ item }) {
    const classes = useStyles()
    const [expanded, setExpanded] = useState(false)
    const handleExpand = () => {
        setExpanded(!expanded)
    }

    return (
        <Grid item xs={12} sm={6} lg={3}>
            <Card variant="outlined" className={classes.card}>
                <Tooltip title={<Typography variant="subtitle2">{item.name}</Typography>} placement="right">
                    <div>
                    <CardHeader
                        title={item.name}
                        subheader={`(${item.start}-${item.end})`}
                        className={classes.cardHeader}
                        titleTypographyProps={{
                            noWrap: true
                        }}
                    />
                    </div>
                </Tooltip>
                <CardContent className={classes.content}>
                    <Typography variant="body1">
                        {item.description}
                    </Typography>
                    <ul className={classes.achievements}>
                        {
                            item.achievements.map((achievement, idx) => (
                                    <li key={idx}>
                                        <Typography variant="subtitle2">{achievement}</Typography>    
                                    </li>
                                )
                            )
                        }
                    </ul>
                </CardContent>
                <CardActions disableSpacing className={classes.cardActions}>
                    <div>
                        <a href={item.code} target="_blank" rel="noreferrer">
                            <IconButton disabled={!item.code}>
                                    <GitHubIcon />
                            </IconButton>
                        </a>
                        <a href={item.link} target="_blank" rel="noreferrer">
                            <IconButton disabled={!item.link}><LaunchIcon /></IconButton>
                        </a>
                    </div>
                    <IconButton onClick={handleExpand}><ExpandMoreIcon /></IconButton>
                </CardActions>
                <Collapse in={expanded}>
                    <CardContent>
                    
                    {/* Tags */}
                    {
                        item.tags.map((tag, idx) => (
                                <Chip key={idx} color="primary" className={classes.chip} variant='outlined' label={tag} />
                            )
                        )
                    }
                    </CardContent>
                </Collapse>
            </Card>
        </Grid>
    )
}

export default SingleProject