Object.values(data).forEach(
    (item, idx) => {
        item.order = idx // Sorting order
        if(item.courses.length !== 0) {
            // Is specialization
            item.order = Object.keys(data).length + idx //Last added specializations first
            const s = new Set()
            item.courses = item.courses.map(key => {
                data[key].tags.forEach((tag) => s.add(tag))
                return data[key]
            })
            item.tags = Array.from(s)
        }
    }
)

export default data