import { Grid, makeStyles, Typography, CardActionArea } from '@material-ui/core'
import React from 'react'
import ContactForm from '../components/ContactForm'

import data from '../data/contact'

const useStyles = makeStyles(theme => ({
		icon: {
			fontSize: theme.typography.h2.fontSize
		},
		actionarea: {
			width: "fit-content !important",
			padding: theme.spacing(2),
			display: "flex !important"
		}, 
	})
)
function Contact() {
	const classes = useStyles()

	return (
		<Grid container justifyContent="center">
			{/* Form */}
			<Grid container item xs={12} justifyContent="center">
				<Grid item xs={12}>
					<Typography variant="h2" align="center" gutterBottom>Reach me directly using the form!</Typography>
				</Grid>
				<ContactForm />
			</Grid>
			{/* Links */}
			{
				data.map((item, idx) => (
					<Grid key={idx} container justifyContent="center" item xs={6} sm={3} component="a" href={item.value} target="_blank" rel="noreferrer">
						<Grid item container component={CardActionArea} className={classes.actionarea}>
							<Grid item>
								<item.icon className={classes.icon} />
							</Grid>
							<Grid item xs={12}>
								<Typography align="center" className={classes.iconDisplay}>
									{item.display}
								</Typography>
							</Grid>
						</Grid>
					</Grid>
					)
				)
			}
		</Grid>
	)
}

export default Contact