import { makeStyles, Toolbar, alpha, Typography, MenuItem, ListItemIcon, useMediaQuery, useTheme } from '@material-ui/core'
import React from 'react'
import URLs from '../utils/urls'
import { Link } from 'react-router-dom'


const useStyles = makeStyles((theme)=>({
	appbar: {
		backgroundColor: alpha(theme.palette.background.default, 0.75),
		position: 'sticky', top: 0,
		zIndex: 10,
		padding: "0.5rem 1rem",
		justifyContent: "space-around",
		overflow: "hidden"
	},
	menuitem: {
		display: "flex",
		flexGrow: 1,
		justifyContent: "center"
	},
	icon: {
		fill: theme.palette.text.primary,
		height: theme.typography.h6.fontSize, 
		width: 'auto',
		marginRight: theme.spacing(1.5),
		marginLeft: 'auto',
		strokeWidth: "1px",
		[theme.breakpoints.down('xs')]: {
			height: theme.typography.h5.fontSize,
		}
	},
	link: {
		textDecoration: "none",
		color: "inherit"
	}
	})
)

function Navbar() {
	const classes = useStyles()
	const theme = useTheme()
	const isMobile = useMediaQuery(theme.breakpoints.down('xs'))
	return (
		<Toolbar className={classes.appbar}>
			{
				Object.values(URLs).map((item, idx) => (
						<Link key={idx} to={item.route} className={classes.link}>
						<MenuItem className={classes.menuitem}>
							<ListItemIcon fontSize="small">
								<item.logo className={classes.icon}/>
							</ListItemIcon>
							{
								isMobile?null:
								<Typography variant="h6"> {item.display} </Typography>
							}
						</MenuItem>
						</Link>
					)
				)
			}
		</Toolbar>
	)
}

export default Navbar