import { List, ListItem, ListItemText, makeStyles, Paper } from '@material-ui/core'
import React from 'react'

const useStyles = makeStyles(theme=>({
        root: {
            backgroundColor: theme.palette.background.default,
            padding: theme.spacing(2.5)
        },
        bullet: {
            display: 'inline-block',
            margin: '0 2px',
            transform: 'scale(1.2)',
        },
        heading: {
            fontFamily: "Lato",
        }
    })
)
function ExtraCurricular({ data, className }) {
    const classes = useStyles()

    return (<Paper variant="outlined" className={`${classes.root} ${className}`}>
        <List>
        {
            data.map((item,idx)=>(
                <ListItem key={idx}>
                    <ListItemText primary={item.title} secondary={item.description} primaryTypographyProps={{className: classes.heading}} />
                </ListItem>
                )
            )
        }
        </List>
    </Paper>
    )
}

export default ExtraCurricular