import React, { useState } from 'react'
import ExpandMoreIcon from '@material-ui/icons/ExpandMore';
import { Accordion, AccordionDetails, AccordionSummary, makeStyles, Typography } from '@material-ui/core';

const useStyles = makeStyles(theme => ({
        root: {
            border: `1px solid ${theme.palette.divider}`
        },
        accordionSummary: {
            // display: "flex", width: "100%",
            // justifyContent: "space-between"
        },
        header: {
            fontFamily: "Lato",
            fontWeight: "bold"
        },
        accordion: {
            backgroundColor: theme.palette.background.default,
        },
    })
)


function Education({ data, className }) {
    const classes = useStyles()
    const [expanded, setExpanded] = useState(false);
    const handleChange = (panel) => (event, isExpanded) => {
        setExpanded(isExpanded ? panel : false)
    }
    return (<div className={`${classes.root} ${className}`}>
    {
        data.map(
            (item, idx) => (
            <Accordion key={idx} className={classes.accordion} expanded={expanded===item.id} onChange={handleChange(item.id)}>
                <AccordionSummary expandIcon={<ExpandMoreIcon />} className={classes.accordion}>
                    <div className={classes.accordionSummary}>
                        <Typography variant="h6" className={classes.header}>{item.institute}</Typography>
                        <Typography color="textSecondary" variant="subtitle1" className={classes.header}>({item.start}-{item.end})</Typography>
                    </div>
                </AccordionSummary>
                <AccordionDetails>
                    <div>
                    <Typography variant="h6">
                        Degree: {item.degree}
                    </Typography>
                    <Typography variant="h6">
                        {item.score[0]}: {item.score[1]}{item.score[2]}
                    </Typography>
                    <ul>
                        {
                            item.list.map((listItem, idx) => (<li key={idx}>
                                    <Typography variant='body1'>
                                            {listItem}
                                    </Typography>
                                </li>)
                            )
                        }
                    </ul>
                    </div>
                </AccordionDetails>
            </Accordion>
            )
        )
    }
    </div>)
}

export default Education