import { Grid, makeStyles } from '@material-ui/core'
import { Pagination } from '@material-ui/lab'
import React, { useState } from 'react'
import SingleCertificate from '../components/SingleCertificate'

import data from '../data/certificate'

const useStyles = makeStyles((theme)=>({
		root: {
			width: "100%"
		},
		certificates: {
			marginBottom: theme.spacing(3)
		},
	})
)
function Certificates() {
	const classes = useStyles()
	const [page, setPage] = useState(1)
	const handleChange = (event, value) => {
		setPage(value)
	}
	
	const itemsPerPage = 4
	const count = Math.ceil(Object.keys(data).length/itemsPerPage)
	const start = (page - 1)*itemsPerPage
	const end   = start + itemsPerPage
	return (<Grid container justifyContent="center" className={classes.root}>
		<Grid item container xs={12} className={classes.certificates} spacing={1}>
			{
				(Object.values(data))
				.sort(
					(a,b) => (
						a.order > b.order?-1:
						b.order > a.order?1:
						0
					)
				)
				.slice(start, end).map(
					(item, idx) => (
						<SingleCertificate key={idx} item={item}/>
					)
				)
			}
		</Grid>
		<Grid item>
			<Pagination size="large" variant="outlined" color="secondary" count={count} page={page} onChange={handleChange} />
		</Grid>
	</Grid>
	)
}

export default Certificates