import { Box, makeStyles, alpha } from '@material-ui/core'
import React from 'react'
import Navbar from '../components/Navbar'
const useStyles = makeStyles((theme)=>({
	container: {
		position: "relative",
		backgroundColor: alpha(theme.palette.background.default, 1),
		width: "70vw",
		[theme.breakpoints.down('xl')]: {width: '85vw'},
		[theme.breakpoints.down('sm')]: {width: '90vw'},
		[theme.breakpoints.down('xs')]: {width: '95vw'},
		margin: "auto",
		marginBottom: theme.spacing(4),
		boxShadow: `0px 0px 1px 1px ${alpha(theme.palette.text.primary, 0.3)}`,
		marginTop: theme.spacing(2),
		padding: theme.spacing(3),
		borderRadius: theme.spacing(3)
	}
})
)
function Template({children}) {
	const classes = useStyles()
    return (<>
		<Navbar />
		<Box className={classes.container}>
			{children}
		</Box>
	</>
  )
}

export default Template