import { Card, Grid, makeStyles, CardContent, CardActionArea, Typography, useTheme, useMediaQuery, Chip } from '@material-ui/core'
import React from 'react'
import CertificateCollapse from './CertificateCollapse'
const useStyles = makeStyles(theme=>({
        card: {
            height: "100%",
            backgroundColor: theme.palette.background.default
        },
        img: {
            height: 'auto',
            maxWidth: '100%',
            maxHeight: 300,
            verticalAlign: "middle"
        },
        chip: {
            margin: theme.spacing(0.35),
            fontSize: theme.typography.body2.fontSize,
            fontWeight: theme.typography.body2.fontWeight
        },
        area: {
            height: '100%'
        },
        subtextContainer: {
            display: "flex",
            justifyContent: "space-between",
            marginBottom: theme.spacing(1),
        },
        expand: {
            display: "flex",
            width: "100%",
            flexDirection: "column",
            alignItems: "center"
        }
    })
)

function SingleCertificate({item}) {
    const classes = useStyles()
    const theme = useTheme()
	const isMobile = useMediaQuery(theme.breakpoints.down('sm'))
    const isXs     = useMediaQuery(theme.breakpoints.down('xs'))
    const isSpecialization = item.courses.length !== 0

    return (<>
            <Grid item container xs={12} sm={4} md={3} justifyContent="flex-end" alignItems="center" className={classes.imageContainer}>
                <Grid item>
                    <img src={item.image} className={classes.img} alt={`${item.name} course certificate`}/>
                </Grid>
            </Grid>
            <Grid item xs={12} sm={8} md={9}>
                <Card variant="outlined" className={classes.card}>
                    <a href={item.verify} target="_blank" rel="noreferrer">
                        <CardActionArea className={isSpecialization?null:classes.area}>
                            <CardContent className={classes.area}>
                                <Typography gutterBottom className={classes.heading} variant={isMobile?"h5":"h4"}>
                                    {item.name}
                                </Typography>
                                <div className={classes.subtextContainer}>
                                    <Typography variant={isXs?"body2":"body1"}>
                                        Offered by: {item.offered_by}
                                    </Typography>    
                                    <Typography variant={isXs?"subtitle2":"subtitle1"}>
                                        {item.date}
                                    </Typography>
                                </div>
                                {/* Tags */}
                                {
                                    item.tags.map((tag, idx) => (
                                            <Chip key={idx} color="primary" className={classes.chip} variant='outlined' label={tag} />
                                        )
                                    )
                                }
                                
                            </CardContent>
                        </CardActionArea>
                    </a>
                    <div className={classes.expand}>
                    {
                        isSpecialization?
                        <CertificateCollapse courses={item.courses}/>
                        :null
                    }
                    </div>
                </Card>
            </Grid>
        </>
    )
}

export default SingleCertificate