import { Button, Grid, makeStyles, TextField } from '@material-ui/core'
import { Alert } from '@material-ui/lab'
import axios from 'axios'
import React, { useState } from 'react'

const useStyles = makeStyles(theme => ({
        form: {
			width: "100%",
			marginBottom: theme.spacing(3)
		},
		textfield: {
			marginBottom: theme.spacing(1)
		},
        btn: {
			margin: "auto",
			minWidth: 200
		},
		btnContainer: {
			width: "100%",
			display: "flex"
		}
    })
)

function ContactForm() {
    const classes = useStyles()
    const [name, setName] = useState(null)
	const [email, setEmail] = useState(null)
	const [message, setMessage] = useState(null)
	const [displayAlert, setDisplayAlert] = useState(false)
	const [severity, setSeverity] = useState("info")
	const [alertText, setAlertText] = useState("Sending mail...")
    const [loading, setLoading] = useState(false)
	const emailError = (mail) => {
		if(mail === null) { return false }
		//eslint-disable-next-line
		return !(/^\w+([\.-]?\w+)*@\w+([\.-]?\w+)*(\.\w{2,3})+$/.test(mail))
	}
    const handleSubmit = () => {
        setDisplayAlert(false)
		if(
			name===null || email === null || message === null || 
			name==="" || message === "" || email === "" ||
			emailError(email)
		) { 
			setSeverity("error")
			setAlertText("Please correctly fill out all fields!")
			setDisplayAlert(true)
			return null
		}
		const data = new FormData()
		data.append("name", name)
		data.append("email", email)
		data.append("message", message)

		const config = {
			method:"POST",
			url: process.env.REACT_APP_MAILING,
			data: data
		}
        setName("")
        setEmail("")
        setMessage("")
        setLoading(true)
		axios(config)
		.then(res => {
			setSeverity("success")
			setAlertText("Success! I'll respond to you soon :)")
            setName(null)
            setEmail(null)
            setMessage(null)
            setLoading(false)
            setDisplayAlert(true)
		})
		.catch(err => {
			setSeverity("error")
			setAlertText("Oops! Looks like something went wrong. Please try again in later")
            setName(null)
            setEmail(null)
            setMessage(null)
            setLoading(false)
            setDisplayAlert(true)
		})
	}

    return (
        <Grid item xs={12} sm={6} lg={4}>
        <form className={classes.form}>
            <TextField error={name === "" && !loading} className={classes.textfield} variant="outlined" fullWidth value={name} onChange={e => setName(e.target.value)} label='Name' placeholder='Enter your name' />
            <TextField error={(email === "" || emailError(email)) && !loading} className={classes.textfield} variant="outlined" fullWidth value={email} onChange={e => setEmail(e.target.value)} label='Email'  placeholder='Enter your email' />
            <TextField error={message === "" && !loading} className={classes.textfield} variant="outlined" fullWidth value={message} onChange={e => setMessage(e.target.value)} label='Message' placeholder='Write me a message!' multiline minRows={5} maxRows={8} />
            <div className={classes.btnContainer}>
                <Button disabled={loading} onClick={handleSubmit} className={classes.btn} variant="outlined" color="secondary">Submit</Button>
            </div>
        </form>
        {
            displayAlert?(
                <Alert severity={severity}> 
                    {alertText}
                </Alert>
            ): null
        }
        </Grid>
    )
}

export default ContactForm