import { Button, CardContent, Collapse, makeStyles, Paper, Typography } from '@material-ui/core'
import { Timeline, TimelineConnector, TimelineContent, TimelineDot, TimelineItem, TimelineOppositeContent, TimelineSeparator } from '@material-ui/lab'
import React, { useState } from 'react'
import ExpandMoreIcon from '@material-ui/icons/ExpandMore';
import ExpandLessIcon from '@material-ui/icons/ExpandLess';

const useStyles = makeStyles(theme => ({
        paper: {
            padding: `${theme.spacing(1)}px ${theme.spacing(2)}px`,
        },
		mb: {
			marginBottom: theme.spacing(1.5)
		},
    })
)

function CertificateCollapse({courses}) {
    const [expanded, setExpanded] = useState(false)
    const handleClick = () => {
        setExpanded(!expanded)
    }
    const classes = useStyles()
    return (
        <>
        <Button className={classes.mb} onClick={handleClick} color="secondary" variant="outlined"> 
            {expanded?"Hide":"View"} Specialization Courses
            {expanded?<ExpandLessIcon />:<ExpandMoreIcon />}
        </Button>
        <Collapse in={expanded} timeout="auto" unmountOnExit>
            <CardContent>
                <Timeline align="alternate">
                {
                    [...courses].reverse().map((course, idx) => (
                        <TimelineItem key={idx}>
                            <TimelineOppositeContent>
                                <Typography variant="subtitle1">
                                    {course.date}
                                </Typography>
                            </TimelineOppositeContent>
                            <TimelineSeparator>
                                <TimelineDot color="primary" />
                                {idx+1===courses.length?null:<TimelineConnector />}
                            </TimelineSeparator>
                            <TimelineContent>
                                <Paper variant="outlined" className={classes.paper}>
                                    <Typography variant="body1">
                                        {course.name}
                                    </Typography>
                                </Paper>
                            </TimelineContent>
                        </TimelineItem>
                        )
                    )
                }
                </Timeline>
            </CardContent>
        </Collapse>
        </>
    )
}

export default CertificateCollapse