import { Card, CardActionArea, CardContent, Grid, makeStyles, Typography } from '@material-ui/core'
import React from 'react'

const useStyles = makeStyles(theme => ({
        link: {
            textDecoration: "none",
            color: "inherit"
        },
        heading: {
            fontFamily: "Lato",
            fontWeight: "bold"
        },
        card: {
            height: "100%"
        },
        mbsmall: {
            [theme.breakpoints.down('xs')]: {
                marginBottom: theme.spacing(1.5)
            }
        }
    })
)
function OrganizationCards({ data, className }) {
    const classes = useStyles()
    return (<Grid container className={`${className}`} justifyContent="space-around">
        {
            data.map((item, idx)=>(
                <Grid key={idx} item xs={12} sm={3} className={classes.mbsmall}>
                    <a href={item.link} target="_blank" rel="noreferrer" className={classes.link}>
                    <Card variant="outlined" className={classes.card}>
                        <CardActionArea className={classes.card}>
                            <CardContent>
                                <Typography className={classes.heading} variant="h5" align="center">
                                    {item.name}
                                </Typography>
                                <Typography color="textSecondary" className={classes.heading} variant="subtitle2" align="center">
                                    ({item.start}-{item.end})
                                </Typography>
                                <Typography align="center">
                                    {item.role}
                                </Typography>
                            </CardContent>
                        </CardActionArea>
                    </Card>
                    </a>
                </Grid>
                )
            )
        }
    </Grid>
    )
}

export default OrganizationCards