const opts = (theme) => ({
    background: {
        color: {
            value: theme.palette.background.default
        }
    },
    particles: {
        number: {
        value: 70,
            density: {
                enable: true,
                value_area: 1000
            }
        },
        color: {
            value: theme.palette.text.primary
        },
        shape: {
            type: 'circle',
            stroke: {
                width: 0,
                color: theme.palette.info.main
            },
            polygon: {
                nb_sides: 5
            },
            image: {
                src: '',
                width: 100,
                height: 100
            }
        },
        opacity: {
            value: 0.5,
            random: false,
            anim: {
                enable: false,
                speed: 1,
                opacity_min: 0.1,
                sync: false
            }
        },
        size: {
            value: 5,
            random: true,
            anim: {
                enable: false,
                speed: 40,
                size_min: 0.1,
                sync: false
            }
        },
        line_linked: {
            enable: true,
            distance: 150,
            color: theme.palette.text.primary,
            opacity: 0.4,
            width: 1
        },
        move: {
            enable: true,
            speed: 1,
            direction: 'none',
            random: false,
            straight: false,
            out_mode: 'out',
            bounce: false,
            attract: {
                enable: false,
                rotateX: 600,
                rotateY: 1200
            }
        },
        array: []
    },
    interactivity: {
        detect_on: 'canvas',
        events: {
            onhover: {
                enable: true,
                mode: 'grab'
            },
            onclick: {
                enable: true,
                mode: 'push'
            },
        resize: true
        },
        modes: {
            grab:{
                distance: 400,
                line_linked:{
                    opacity: 1
                }
            },
            bubble:{
                distance: 400,
                size: 40,
                duration: 2,
                opacity: 8,
                speed: 3
            },
            repulse:{
                distance: 200
            },
            push:{
                particles_nb: 4
            },
            remove:{
                particles_nb: 2
            }
        },
        mouse:{}
    },
    retina_detect: false,
    fn: {
        interact: {},
        modes: {},
        vendors:{}
    },
    tmp: {}
})
export default opts