import React, {useContext} from 'react'
import { tsParticles } from "tsparticles";
import particleOptions from './utils/particleOptions'
import { CssBaseline, ThemeProvider } from '@material-ui/core'
import { HashRouter, Route, Routes } from 'react-router-dom';
// Page Imports
import Home from './pages/Home'
import Contact from './pages/Contact'
import Certificates from './pages/Certificates'
import Projects from './pages/Projects'
import Template from './pages/Template';
import NotFound from './pages/NotFound';
import Introduction from './pages/Introduction';

// Utils
import darkTheme from './utils/darkTheme';
import lightTheme from './utils/lightTheme'
import URLs from './utils/urls'

const localTheme = localStorage.getItem('localTheme')	// Will be stored on toggle
const ThemeContext = React.createContext(localTheme==='light'?lightTheme:darkTheme);

function App() {
	const theme = useContext(ThemeContext)
	tsParticles.load("tsparticles", particleOptions(theme))
	return (
	<ThemeProvider theme={theme}>
		<CssBaseline />
		<HashRouter>
			<Routes>
				<Route path={URLs.home.route} element={<Introduction />}/>
			</Routes>
			<Template>
			<Routes>
				<Route path={URLs.home.route} element={<Home />}/>
				<Route path={URLs.certificates.route} element={<Certificates />}/>
				<Route path={URLs.projects.route} element={<Projects />}/>
				<Route path={URLs.contact.route} element={<Contact />}/>
				<Route path="*" element={<NotFound />}/>
			</Routes>
			</Template>
		</HashRouter>
	</ThemeProvider>
	);
}

export default App;
