import { makeStyles, Typography } from '@material-ui/core'
import React from 'react'
import EducationAccordion from '../components/EducationAccordion'
import ExtraCurricular from '../components/ExtraCurricular'
import OrganizationCards from '../components/OrganizationCards'
import SkillChips from '../components/SkillChips'
import data from '../data/home'

const useStyles = makeStyles(theme => ({
		heading: {
			fontFamily: "Lato"
		},
		mb3: {
			marginBottom: theme.spacing(3)
		}
	})
)

function Home() {
	const classes = useStyles()
	return (<>
		{/* Education */}
		<Typography variant="h3" className={classes.heading} gutterBottom>Educational History</Typography>
		<hr />
		<EducationAccordion className={classes.mb3} data={data.education} />
		{/* Skills */}
		<Typography variant="h3" className={classes.heading} gutterBottom>Skill Set</Typography>
		<hr />
		<SkillChips className={classes.mb3} data={data.skills} />
		{/* Organizations */}
		<Typography variant="h3" className={classes.heading} gutterBottom>Organizations</Typography>
		<hr />
		<OrganizationCards className={classes.mb3} data={data.organizations}/>
		<Typography variant="h3" className={classes.heading} gutterBottom>Extra-Curricular Experience</Typography>
		<hr />
		<ExtraCurricular className={classes.mb3} data={data.extra}/>
	</>
	)
}

export default Home