import React from 'react'
import { Grid, makeStyles, Typography } from '@material-ui/core'
import data from '../data/introduction'

const useStyles = makeStyles((theme)=>({
		root: {
			padding: "2rem 1rem",
			[theme.breakpoints.up('sm')]: {padding: "4rem 2rem"},
			position: "relative",
		},
		img: {
			maxWidth: "100%",
			height: "auto",
			maxHeight: 300,
			border: `0.25rem solid ${theme.palette.text.primary}`,
    		borderRadius: "0.35rem",
		},
		textContainer: {
			paddingLeft: theme.spacing(3),
			paddingRight: theme.spacing(3),
			[theme.breakpoints.down('xs')]: {
				textAlign: "center",
				padding: 0,
			}
		},
		name: {fontFamily:"Polya", display: "inline"},
		role: {fontSize: "1.15rem", fontFamily: "Lato", fontWeight: 500}
	})
)

function Introduction() {
	const classes = useStyles()
	const [fName, lName] = data.name.split(' ')
	const name = [fName, " ", lName]
	return (
		<Grid container className={classes.root} justifyContent="center" alignItems="center">
			<Grid item xs={12} sm={4} align="center">
				<img src={data.img} alt="thumbnail.jpg" className={classes.img}/>
			</Grid>
			<Grid item xs={12} sm={8} lg={6} className={classes.textContainer}>
				<div>
					{
						name.map((item, idx) => (
								<React.Fragment key={idx}>
									<Typography variant="h1" className={classes.name}>
										{item[0]}
									</Typography>
									<Typography variant="h2" className={classes.name}>
										{item.slice(1)}
									</Typography>
								</React.Fragment>
							)
						)
					}
				</div>
				<Typography className={classes.role} variant="h6">
					{data.roles.join(" | ")}
				</Typography>
				<hr/>
				<Typography className={classes.subtext} variant="h5">
					{data.subtext}
				</Typography>
			</Grid>
		</Grid>
	)
}

export default Introduction